mapper.update:
UPDATE account_lock_state
SET failed_login_count = 0,
    last_failed_at     = NULL,
    updated_at         = #{now}
WHERE user_id   = #{userId}
  AND user_type = #{userType}

mapper.select:
SELECT *
FROM account_lock_state
WHERE locked = 1
  AND locked_until IS NOT NULL
  AND locked_until <= #{now}
  AND id > #{afterId}
ORDER BY id ASC
LIMIT #{pageSize}
